Certainly! Setting up an AWS environment using Terraform involves organizing your code into modules that are reusable and maintainable. Below is a suggested directory structure and example files to help you get started with a clean Terraform setup for networking, EKS (Elastic Kubernetes Service), and shared security controls.

### Directory Structure

```
terraform-aws-platform/
├── main.tf
├── variables.tf
├── outputs.tf
└── modules/
    ├── network/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
    ├── eks/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
    └── security/
        ├── main.tf
        ├── variables.tf
        └── outputs.tf
```

### Explanation of Files and Directories

1. **main.tf**: Entry point for your Terraform configuration.
2. **variables.tf**: Declares input variables used in the Terraform configuration.
3. **outputs.tf**: Defines output values that can be consumed by other modules or scripts.
4. **modules/**: Contains subdirectories for each module (network, eks, security).

### Example Files

#### `main.tf`

```hcl
provider "aws" {
  region = var.region
}

module "network" {
  source              = "./modules/network"
  vpc_cidr            = var.vpc_cidr
  public_subnets      = var.public_subnets
  private_subnets     = var.private_subnets
  azs                 = var.azs
  enable_nat_gateway  = var.enable_nat_gateway
}

module "eks" {
  source              = "./modules/eks"
  vpc_id              = module.network.vpc_id
  subnets             = module.network.public_subnets
  cluster_name        = var.cluster_name
  node_group_name     = var.node_group_name
  desired_size        = var.desired_size
}

module "security" {
  source              = "./modules/security"
  vpc_id              = module.network.vpc_id
  security_groups     = [module.eks.security_group]
}
```

#### `variables.tf`

```hcl
variable "region" {
  description = "The AWS region to deploy the resources."
}

variable "vpc_cidr" {
  description = "CIDR block for the VPC."
}

variable "public_subnets" {
  description = "List of public subnet CIDRs."
}

variable "private_subnets" {
  description = "List of private subnet CIDRs."
}

variable "azs" {
  description = "List of availability zones to use."
}

variable "enable_nat_gateway" {
  description = "Whether to enable NAT Gateway for the VPC."
}

variable "cluster_name" {
  description = "Name of the EKS cluster."
}

variable "node_group_name" {
  description = "Name of the node group in the EKS cluster."
}

variable "desired_size" {
  description = "Desired size of the node group."
}
```

#### `outputs.tf`

```hcl
output "vpc_id" {
  value = module.network.vpc_id
}

output "eks_cluster_endpoint" {
  value = module.eks.cluster.endpoint
}

output "security_group_ids" {
  value = [module.security.security_group_id]
}
```

### Network Module (`modules/network`)

#### `main.tf`

```hcl
resource "aws_vpc" "vpc" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
}

resource "aws_subnet" "public_subnets" {
  count                = length(var.public_subnets)
  vpc_id               = aws_vpc.vpc.id
  cidr_block           = element(var.public_subnets, count.index)
  availability_zone    = element(var.azs, count.index)
  map_public_ip_on_launch = true
}

resource "aws_subnet" "private_subnets" {
  count                = length(var.private_subnets)
  vpc_id               = aws_vpc.vpc.id
  cidr_block           = element(var.private_subnets, count.index)
  availability_zone    = element(var.azs, count.index)
  map_public_ip_on_launch = false
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_nat_gateway" "nat_gw" {
  count                = length(var.public_subnets) > 0 ? var.enable_nat_gateway : 0
  allocation_id        = aws_eip.nat_gw[count.index].id
  subnet_id            = element(aws_subnet.public_subnets.*.id, count.index)
}

resource "aws_eip" "nat_gw" {
  count                = length(var.public_subnets) > 0 ? var.enable_nat_gateway : 0
  vpc                  = true
}
```

#### `variables.tf`

```hcl
variable "vpc_cidr" {
  description = "CIDR block for the VPC."
}

variable "public_subnets" {
  description = "List of public subnet CIDRs."
}

variable "private_subnets" {
  description = "List of private subnet CIDRs."
}

variable "azs" {
  description = "List of availability zones to use."
}

variable "enable_nat_gateway" {
  description = "Whether to enable NAT Gateway for the VPC."
}
```

#### `outputs.tf`

```hcl
output "vpc_id" {
  value = aws_vpc.vpc.id
}

output "public_subnets" {
  value = aws_subnet.public_subnets.*.id
}

output "private_subnets" {
  value = aws_subnet.private_subnets.*.id
}
```

### EKS Module (`modules/eks`)

#### `main.tf`

```hcl
resource "aws_eks_cluster" "cluster" {
  name     = var.cluster_name
  role_arn = data.aws_iam_role.cluster.arn

  vpc_config {
    subnet_ids = var.subnets
  }
}

data "aws_iam_role" "cluster" {
  name = "${var.cluster_name}-node"
}

resource "aws_eks_node_group" "node_group" {
  cluster_name = aws_eks_cluster.cluster.name
  node_group_name = var.node_group_name
  node_role_arn   = data.aws_iam_role.cluster.arn

  subnet_ids         = var.subnets
  desired_size       = var.desired_size
}

output "cluster_endpoint" {
  value = aws_eks_cluster.cluster.endpoint
}

output "security_group" {
  value = aws_security_group.node_group.id
}
```

#### `variables.tf`

```hcl
variable "vpc_id" {
  description = "ID of the VPC."
}

variable "subnets" {
  description = "List of subnet IDs for the EKS cluster."
}

variable "cluster_name" {
  description = "Name of the EKS cluster."
}

variable "node_group_name" {
  description = "Name of the node group in the EKS cluster."
}

variable "desired_size" {
  description = "Desired size of the node group."
}
```

#### `outputs.tf`

```hcl
output "cluster_endpoint" {
  value = aws_eks_cluster.cluster.endpoint
}

output "security_group_id" {
  value = aws_security_group.node_group.id
}
```

### Security Module (`modules/security`)

#### `main.tf`

```hcl
resource "aws_security_group" "sg" {
  name        = var.sg_name
  description = "Security group for EKS"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

output "security_group_id" {
  value = aws_security_group.sg.id
}
```

#### `variables.tf`

```hcl
variable "vpc_id" {
  description = "ID of the VPC."
}

variable "sg_name" {
  description = "Name of the security group."
}
```

